function formatDateKey(date: Date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function normalizeDateKeyValue(value: string) {
  if (!value) return "";
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return value;
  const germanDate = parseGermanDate(value);
  return germanDate ? formatDateKey(germanDate) : value;
}

function parseDateKeyValue(value: string) {
  const normalized = normalizeDateKeyValue(value);
  if (!normalized) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(normalized)) {
    const [year, month, day] = normalized.split("-").map((part) => Number(part));
    return new Date(year, month - 1, day, 12);
  }
  return parseGermanDate(value);
}

function parseProjectDate(value?: string) {
  if (!value) return null;

  const normalizedValue = value.trim();
  const isoMatch = normalizedValue.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) {
    const [, yearValue, monthValue, dayValue] = isoMatch;
    const date = new Date(Number(yearValue), Number(monthValue) - 1, Number(dayValue));
    return Number.isFinite(date.getTime()) ? date : null;
  }

  const germanMatch = normalizedValue.match(/^(\d{1,2})\.(\d{1,2})\.(\d{2}|\d{4})/);
  if (germanMatch) {
    const [, dayValue, monthValue, yearValue] = germanMatch;
    const parsedYear = Number(yearValue);
    const year = parsedYear < 100 ? 2000 + parsedYear : parsedYear;
    const date = new Date(year, Number(monthValue) - 1, Number(dayValue));
    return Number.isFinite(date.getTime()) ? date : null;
  }

  const [year, month, day] = normalizedValue.split("-").map(Number);
  if (!year || !month || !day) return null;

  const date = new Date(year, month - 1, day);
  return Number.isFinite(date.getTime()) ? date : null;
}

function formatProjectDate(value?: string) {
  const date = parseProjectDate(value);
  return date
    ? new Intl.DateTimeFormat(APP_LOCALE, {
        dateStyle: "medium",
        timeZone: APP_TIME_ZONE,
      }).format(date)
    : "-";
}

function formatProjectRuntimeDuration(startValue?: string, endValue?: string) {
  const startDate = parseProjectDate(startValue);
  const endDate = parseProjectDate(endValue);

  if (!startDate || !endDate) return "-";
  if (endDate.getTime() < startDate.getTime()) return "Enddatum liegt vor Start";

  let months =
    (endDate.getFullYear() - startDate.getFullYear()) * 12 +
    (endDate.getMonth() - startDate.getMonth());
  let days = endDate.getDate() - startDate.getDate();

  if (days < 0) {
    months -= 1;
    days += new Date(endDate.getFullYear(), endDate.getMonth(), 0).getDate();
  }

  const parts = [
    months > 0 ? `${months} ${months === 1 ? "Monat" : "Monate"}` : "",
    days > 0 ? `${days} ${days === 1 ? "Tag" : "Tage"}` : "",
  ].filter(Boolean);

  return parts.length > 0 ? parts.join(", ") : "0 Tage";
}

function getDefaultDeadlineValue(date = new Date()) {
  return `${formatDateKey(date)}T12:00`;
}

function normalizeDeadlineInput(value: string) {
  const trimmedValue = value.trim();
  if (!trimmedValue) return "";

  const dateOnlyMatch = trimmedValue.match(/^(\d{4}-\d{2}-\d{2})(?:T)?$/);
  if (dateOnlyMatch) return `${dateOnlyMatch[1]}T12:00`;

  const incompleteTimeMatch = trimmedValue.match(/^(\d{4}-\d{2}-\d{2})T(\d{2})(?::)?$/);
  if (incompleteTimeMatch) return `${incompleteTimeMatch[1]}T${incompleteTimeMatch[2]}:00`;

  return trimmedValue;
}

function getMonthDays(date: Date) {
  const year = date.getFullYear();
  const month = date.getMonth();
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);
  const startOffset = (firstDay.getDay() + 6) % 7;
  const days: Array<Date | null> = [];

  for (let index = 0; index < startOffset; index += 1) {
    days.push(null);
  }

  for (let day = 1; day <= lastDay.getDate(); day += 1) {
    days.push(new Date(year, month, day));
  }

  while (days.length % 7 !== 0) {
    days.push(null);
  }

  return days;
}

function getWeekDays(date: Date) {
  const start = new Date(date);
  const dayOffset = (start.getDay() + 6) % 7;
  start.setDate(start.getDate() - dayOffset);
  start.setHours(0, 0, 0, 0);

  return Array.from({ length: 7 }, (_, index) => {
    const day = new Date(start);
    day.setDate(start.getDate() + index);
    return day;
  });
}

function formatWeekTitle(date: Date) {
  const days = getWeekDays(date);
  const first = days[0];
  const last = days[6];
  return `${new Intl.DateTimeFormat(APP_LOCALE, {
    day: "2-digit",
    month: "2-digit",
    timeZone: APP_TIME_ZONE,
  }).format(
    first
  )} - ${new Intl.DateTimeFormat(APP_LOCALE, {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    timeZone: APP_TIME_ZONE,
  }).format(last)}`;
}

function formatDayTitle(date: Date) {
  return new Intl.DateTimeFormat(APP_LOCALE, {
    weekday: "long",
    day: "2-digit",
    month: "long",
    year: "numeric",
    timeZone: APP_TIME_ZONE,
  }).format(date);
}

function formatShortDate(date: Date) {
  return new Intl.DateTimeFormat(APP_LOCALE, {
    weekday: "short",
    day: "2-digit",
    month: "2-digit",
    timeZone: APP_TIME_ZONE,
  }).format(date);
}

function getDeadlineState(value: string) {
  if (!value) return "empty";

  const now = new Date();
  const deadline = new Date(value);
  const isSameDay =
    deadline.getFullYear() === now.getFullYear() &&
    deadline.getMonth() === now.getMonth() &&
    deadline.getDate() === now.getDate();

  if (deadline.getTime() <= now.getTime()) return "due";

  const hoursUntilDeadline = (deadline.getTime() - now.getTime()) / (1000 * 60 * 60);
  if (hoursUntilDeadline <= 24 || isSameDay) return "due";
  if (hoursUntilDeadline <= 48) return "soon";

  return "open";
}

function getWorkingMillisecondsBetween(start: Date, end: Date, holidayDateKeys: Set<string>) {
  if (end.getTime() <= start.getTime()) return 0;

  let totalMilliseconds = 0;
  const cursor = new Date(start);
  cursor.setHours(0, 0, 0, 0);

  while (cursor.getTime() < end.getTime()) {
    const nextDay = new Date(cursor);
    nextDay.setDate(cursor.getDate() + 1);

    const dayKey = formatDateKey(cursor);
    const dayOfWeek = cursor.getDay();
    const isWorkingDay = dayOfWeek !== 0 && dayOfWeek !== 6 && !holidayDateKeys.has(dayKey);

    if (isWorkingDay) {
      const segmentStart = Math.max(start.getTime(), cursor.getTime());
      const segmentEnd = Math.min(end.getTime(), nextDay.getTime());
      totalMilliseconds += Math.max(0, segmentEnd - segmentStart);
    }

    cursor.setDate(cursor.getDate() + 1);
  }

  return totalMilliseconds;
}

function getDeadlineProgress(task: TaskItem, nowMs: number, holidayDateKeys: Set<string>) {
  if (!task.faelligkeit || !task.createdAt) return 0;

  const createdAt = parseAppDateTime(task.createdAt);
  const deadline = new Date(task.faelligkeit);
  const now = new Date(nowMs);

  if (!Number.isFinite(createdAt.getTime()) || !Number.isFinite(deadline.getTime())) return 0;
  if (deadline.getTime() <= createdAt.getTime()) return nowMs >= deadline.getTime() ? 100 : 0;

  const totalWorkingMilliseconds = getWorkingMillisecondsBetween(
    createdAt,
    deadline,
    holidayDateKeys
  );
  const elapsedWorkingMilliseconds = getWorkingMillisecondsBetween(
    createdAt,
    now > deadline ? deadline : now,
    holidayDateKeys
  );

  if (totalWorkingMilliseconds <= 0) return nowMs >= deadline.getTime() ? 100 : 0;

  return clampPercent(Math.round((elapsedWorkingMilliseconds / totalWorkingMilliseconds) * 100));
}

function getContentRuntimeProgress(entry: ContentItem, nowMs: number) {
  const createdAt = parseAppDateTime(entry.createdAt).getTime();
  const publicationDate = new Date(`${entry.plannedDate}T${entry.plannedTime || "09:00"}:00`).getTime();

  if (!Number.isFinite(createdAt) || !Number.isFinite(publicationDate)) return 0;
  if (publicationDate <= createdAt) return nowMs >= publicationDate ? 100 : 0;

  return clampPercent(Math.round(((nowMs - createdAt) / (publicationDate - createdAt)) * 100));
}

function getContentRuntimeProgressLabel(progress: number, entry: ContentItem, nowMs: number) {
  const createdAt = parseAppDateTime(entry.createdAt).getTime();
  if (progress === 0 && Number.isFinite(createdAt) && nowMs > createdAt) return "<1";
  return String(progress);
}

function getContentRuntimeProgressWidth(progress: number, entry: ContentItem, nowMs: number) {
  const createdAt = parseAppDateTime(entry.createdAt).getTime();
  if (progress === 0 && Number.isFinite(createdAt) && nowMs > createdAt) return 3;
  return progress;
}

function getReadableContentStatus(status: string) {
  if (status.startsWith("Korrektur")) return "Korrektur nötig";
  if (status.includes("ffentlicht")) return "Veröffentlicht";
  return status;
}

function isContentDone(entry: ContentItem) {
  const status = getReadableContentStatus(entry.status);
  return status === "Freigegeben" || status === "Veröffentlicht";
}

function getContentStatusBadge(entry: ContentItem) {
  const status = getReadableContentStatus(entry.status);
  if (status === "Fertig produziert") {
    return { label: "Fertig produziert", icon: "?", tone: "produced" };
  }
  if (status === "Finale Freigabe offen") {
    return { label: "Finale Freigabe offen", icon: "!", tone: "approval" };
  }
  if (status === "Korrektur nötig") {
    return { label: "Korrektur nötig", icon: "!", tone: "correction" };
  }
  if (status === "Freigegeben") {
    return { label: "Freigegeben", icon: "?", tone: "approved" };
  }
  if (status === "Veröffentlicht") {
    return { label: "Veröffentlicht", icon: "??", tone: "published" };
  }
  return null;
}

