  async function saveUser() {
    if (!userName.trim() || !userEmail.trim()) {
      setErrorMessage("Name und E-Mail sind Pflichtfelder.");
      return false;
    }

    if (!editingUserId && userPassword.trim().length < 4) {
      setErrorMessage("Bitte ein Passwort mit mindestens 4 Zeichen vergeben.");
      return false;
    }

    const res = await fetch("/api/users", {
      method: editingUserId ? "PATCH" : "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        userId: editingUserId,
        name: userName,
        email: userEmail,
        role: userRole,
        password: userPassword,
        dailyWorkHours: Number(userDailyWorkHours),
        profileImageDataUrl: userProfileImageDataUrl,
        salutation: employeeSalutation,
        birthDate: employeeBirthDate,
        language: employeeLanguage,
        phone: employeePhone,
        mobile: employeeMobile,
        street: employeeStreet,
        postalCode: employeePostalCode,
        city: employeeCity,
        signature: employeeSignature,
        signatureHidden: employeeSignatureHidden,
        planningBoard: employeePlanningBoard,
        planningGroup: employeePlanningGroup,
        weeklyCapacity: employeeWeeklyCapacity,
        planningStartTime: employeePlanningStartTime,
        planningEndTime: employeePlanningEndTime,
        planningTimeWindows: employeePlanningTimeWindows,
        planningBreakWindows: employeePlanningBreakWindows,
        planningResponsibleFor: employeePlanningResponsibleFor,
        notifyIdeaStore: employeeNotifyIdeaStore,
        mailAccount: employeeMailAccount,
        teamIds: userAllTeams ? teams.map((team) => team.id) : userTeamIds,
        allTeams: userAllTeams,
        actorId: activeUserId,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setErrorMessage(data?.error ?? "Benutzer konnte nicht gespeichert werden.");
      return false;
    }

    const savedUser = (await res.json()) as UserOption;
    if (userPassword.trim()) {
      setLoginCredentialsDraft({
        name: savedUser.name,
        email: savedUser.email,
        password: userPassword.trim(),
      });
    }

    resetUserForm();
    await loadUsers();
    await loadTasks();
    return true;
  }

  async function saveEmployeePassword() {
    if (!editingUserId) {
      setEmployeePasswordMessage("Neue Mitarbeiter werden mit dem Passwort über Speichern angelegt.");
      return;
    }

    const nextPassword = userPassword.trim();
    if (nextPassword.length < 4) {
      setEmployeePasswordMessage("Bitte ein Passwort mit mindestens 4 Zeichen vergeben.");
      return;
    }

    const res = await fetch("/api/users", {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        userId: editingUserId,
        name: userName,
        email: userEmail,
        role: userRole,
        password: nextPassword,
        dailyWorkHours: Number(userDailyWorkHours),
        profileImageDataUrl: userProfileImageDataUrl,
        teamIds: userAllTeams ? teams.map((team) => team.id) : userTeamIds,
        allTeams: userAllTeams,
        actorId: activeUserId,
      }),
    });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setEmployeePasswordMessage(data?.error ?? "Passwort konnte nicht gespeichert werden.");
      return;
    }

    const savedUser = (await res.json()) as UserOption;
    setLoginCredentialsDraft({
      name: savedUser.name,
      email: savedUser.email,
      password: nextPassword,
    });
    setUserPassword("");
    setEmployeePasswordMessage("Passwort gespeichert. Der Login funktioniert jetzt mit dieser E-Mail-Adresse und dem neuen Passwort.");
    await loadUsers();
  }

  function getEmployeeCostDraft(userId: string) {
    return employeeCostCalculations[userId] ?? {
      ...defaultEmployeeCostCalculation,
      userId,
      annualHours: Number(userDailyWorkHours || 8) * 5 * 52,
      hoursPerDay: Number(userDailyWorkHours || 8),
    };
  }

  function updateEmployeeCostDraft(userId: string, patch: Partial<EmployeeCostCalculation>) {
    setEmployeeCostCalculations((current) => ({
      ...current,
      [userId]: {
        ...getEmployeeCostDraft(userId),
        ...patch,
      },
    }));
  }

  async function loadEmployeeCost(userId: string) {
    if (!userId || !activeUserId || !mayAccessEmployeeCosts) return;

    const params = new URLSearchParams({
      userId,
      actorId: activeUserId,
    });
    const res = await fetch(`/api/employee-costs?${params.toString()}`, { cache: "no-store" });

    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setEmployeeCostError(data?.error ?? "Lohnkosten konnten nicht geladen werden.");
      return;
    }

    const data = (await res.json()) as EmployeeCostCalculation;
    setEmployeeCostCalculations((current) => ({ ...current, [userId]: data }));
    setEmployeeCostError("");
  }

  async function saveEmployeeCost(userId: string) {
    if (!userId || !activeUserId || !mayAccessEmployeeCosts) return;

    setIsSavingEmployeeCost(true);
    setEmployeeCostError("");
    const draft = getEmployeeCostDraft(userId);
    const res = await fetch("/api/employee-costs", {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        ...draft,
        userId,
        actorId: activeUserId,
      }),
    });

    setIsSavingEmployeeCost(false);
    if (!res.ok) {
      const data = await res.json().catch(() => null);
      setEmployeeCostError(data?.error ?? "Lohnkosten konnten nicht gespeichert werden.");
      return;
    }

    const data = (await res.json()) as EmployeeCostCalculation;
    setEmployeeCostCalculations((current) => ({ ...current, [userId]: data }));
  }

